//vip.opstream10.com/20230314/26558_c407363a/index.m3u8"},{"name":"44","slug":"44","filename":"Erkenci Kus 44","link_embed":"https://vip.opstream10.com/share/e273b4b4631a6f6e22eb40b1df2339e9","link_m3u8":"https://vip.opstream10.com/20230316/26603_d1d7a246/index.m3u8"},{"name":"45","slug":"45","filename":"Erkenci 45","link_embed":"https://vip.opstream10.com/share/43e9fffa93004c327ce88972bc528eca","link_m3u8":"https://vip.opstream10.com/20230318/26623_7f48ba34/index.m3u8"},{"name":"46","slug":"46","filename":"Erkenci Kus 46","link_embed":"https://vip.opstream10.com/share/0a979f021ded11b1db1a9468d6a65826","link_m3u8":"https://vip.opstream10.com/20230321/26656_d5f9eb18/index.m3u8"},{"name":"47","slug":"47","filename":"Erkenci Kus 47","link_embed":"https://vip.opstream10.com/share/69a2835d20b8290bc7984b8aa6538f89","link_m3u8":"https://vip.opstream10.com/20230323/26669_d6bdfa7d/index.m3u8"},{"name":"48","slug":"48","filename":"Erkenci Kus 48","link_embed":"https://vip.opstream10.com/share/ffc7ad29e9362b828655bba4a3fe60dc","link_m3u8":"https://vip.opstream10.com/20230326/26687_54148431/index.m3u8"},{"name":"49","slug":"49","filename":"Erkenci Kus 49","link_embed":"https://vip.opstream10.com/share/610126195c0f6e4df38f399c3325aecb","link_m3u8":"https://vip.opstream10.com/20230328/26722_ab0c3f80/index.m3u8"},{"name":"50","slug":"50","filename":"Erkenci Kus 50","link_embed":"https://vip.opstream10.com/share/b6c4f99ebc0cec07eac2d98133094f54","link_m3u8":"https://vip.opstream10.com/20230330/26756_f6da5eeb/index.m3u8"},{"name":"51","slug":"51","filename":"Erkenci Kus 51","link_embed":"https://vip.opstream10.com/share/3b74ab8eb83faf0992aad7a123d02707","link_m3u8":"https://vip.opstream10.com/20230401/26780_6bf3e0f7/index.m3u8"}]}],"time":"120p/tập","description":"<p>Sanem là một phụ nữ trẻ khao khát trở thành nhà văn và sống trên quần đảo Galápagos. Mặc dù làm việc tại cửa hàng tạp hóa của cha cô, cô buộc phải lựa chọn giữa cuộc hôn nhân sắp đặt với người hàng xóm Muzaffer và tìm một công việc phù hợp. Sanem nhận được một công việc tại Fikri Harika, một trong những công ty quảng cáo hàng đầu của Thổ Nhĩ Kỳ, nơi Leyla, chị gái của cô, là trợ lý điều hành. Ông chủ công ty quảng cáo Azizi có hai con trai là Emre và Can. Emre muốn tiếp quản công ty, nhưng cha anh tin rằng Can phù hợp hơn với công việc và anh được bổ nhiệm làm quản lý. Can có những gì cha anh ấy muốn cho công ty, nhưng anh ấy thích chụp ảnh ở những địa điểm xa hơn. Khi biết được vấn đề sức khỏe của cha mình, Can cuối cùng đã đồng ý điều hành công ty. Aziz cũng bảo Can tìm ra tên gián điệp trong công ty đang giúp đỡ đối thủ của họ, Aylin. Emre không thích ý tưởng để anh trai mình làm quản lý và tin rằng anh ấy nên có vị trí này. Kế hoạch của Emre là khiến anh ta thất bại, đồng thời tự mình trở thành gián điệp. Sanem tình cờ gặp Can trên ban công tối tại một bữa tiệc opera kỷ niệm 40 năm thành lập công ty. Can nghĩ rằng cô ấy là bạn gái của anh ấy, Polen, vì vậy anh ấy đã hôn cô ấy. Sanem nhận ra rằng cô ấy yêu người lạ đã hôn cô ấy, và đặt cho anh ta mật danh là Albatross, nhưng lại ghét Can, và Emre khiến cô ấy tin rằng Can chỉ muốn tăng giá trị của công ty để có thể bán được nó. Can nhanh chóng yêu Sanem, và phát hiện ra rằng anh đã hôn cô vào ngày hôm đó tại nhà hát opera, bắt đầu câu chuyện tình yêu không thể tránh khỏi.</p>","tmdb":{"type":"tv","id":"80411","season":1,"vote_average":7.979,"vote_count":96},"modified":"2023-09-05T02:34:38.000Z"},{"id":"63901005be31c1c97db2a5bd","_id":"63901005be31c1c97db2a5bd","title":"Cuộc Tình Tội Lỗi","origin_name":"Unfaithful","slug":"cuoc-tinh-toi-loi","year":2002,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Cuộc Tình Tội Lỗi","link_embed":"https://vip.opstream16.com/share/4d58faf697d47b2ab9908dd1353ac190","link_m3u8":"https://vip.opstream16.com/20221206/26982_e2242d1b/index.m3u8"}]}],"time":"123 phút","description":"<p>Cuộc Tình Tội Lỗi - Unfaithful kể về một đôi vợ chồng sống hạnh phúc ở vùng ngoại ô New York, khi người vợ vướng vào chuyện ái tình với một gã đàn ông Pháp thì cuộc đời của họ đã bị thay đổi theo một chiều hướng không thể nào cứu vãn được....Diễn xuất biểu cảm của Diane Lane, những cảnh chăn gối nóng mắt đã khiến khán giả phải ngồi theo dõi phim từ đầu đến tận phút cuối cùng.</p>","tmdb":{"type":"movie","id":"2251","season":null,"vote_average":6.675,"vote_count":1632},"modified":"2022-12-07T11:01:09.000Z","_image_preserved":true},{"id":"63901022be31c1c97db2a778","_id":"63901022be31c1c97db2a778","title":"Cuộc Chiến Cô Dâu","origin_name":"Bride Wars","slug":"cuoc-chien-co-dau","year":2009,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Cuộc Chiến Cô Dâu","link_embed":"https://vip.opstream16.com/share/64c4c873c60ecf618d5a16ed2ba41651","link_m3u8":"https://vip.opstream16.com/20221206/26981_4c3e9728/index.m3u8"}]}],"time":"88 phút","description":"<p>Cuộc Chiến Cô Dâu - Bride Wars kể về Emma và Liv vốn là đôi bạn thân từ thưở nhỏ, và như bao cô gái khác, cả hai đều có những mơ ước rất lý tưởng dành cho ngày trọng đại trong đời của mình, và gạch đầu dòng đầu tiên cho chuỗi những điều phải làm vào ngày cưới đó là phải tổ chức tại thánh đường dành cho các cô dâu ở New York - khách sạn Plaza. Nay họ đã cùng 26 tuổi, đang cùng nhau hiện thực hóa ước mơ của mình, và tưởng chừng như sẽ là hai cô dâu hạnh phúc nhất, nếu như không họ không phải tranh giành nhau thánh đường trong cùng một ngày. Không ai chịu nhường nhịn ai, và họ bắt đầu cảm thấy khó chịu về người bạn của mình. Khác hẳn với những gì tốt đẹp đã dành cho nhau lúc trước, cả hai bắt đầu ra sức tìm mọi cách để nói xấu và phá hoại đám cưới của người kia. Họ xem nhau như kẻ thù, và giữa họ đã nổ ra trận chiến, một trận chiến thật sự dành cho các cô dâu.</p>","tmdb":{"type":"movie","id":"10521","season":null,"vote_average":6.3,"vote_count":3131},"modified":"2022-12-07T11:01:38.000Z","_image_preserved":true},{"id":"63901079be31c1c97db2ac5b","_id":"63901079be31c1c97db2ac5b","title":"Trái Tim Còn Mãi","origin_name":"Here Awhile","slug":"trai-tim-con-mai","year":2019,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Trái Tim Còn Mãi","link_embed":"https://vip.opstream16.com/share/d9e6b46563c1a62a6d0979d929fe2e6b","link_m3u8":"https://vip.opstream16.com/20221206/26991_2586c849/index.m3u8"}]}],"time":"80 phút","description":"<p>Bộ phim Trái Tim Còn Mãi Sau - Here Awhile kể về cuộc đời của Anna sau khi phát hiện mình bị mắc bệnh nan y; Cô đã quyết định quay về quê nhà Portland Oregon sau 15 năm để gặp lại người em trai xa cách đã lâu là Michael. Tại nơi này cô mong muốn được có cơ hội dành những ngày cuối đời để bên người thân và kết thúc cuộc đời bằng cách sử dụng Đạo luật được chết nhân đạo ở Oregon. Tuy đây là quyết định rất khó khăn và đau đớn nhưng những người thân bên cạnh cô đã quyết định ủng hộ và cùng cô có những tháng ngày cuối cùng thật tươi đẹp và hạnh phúc.</p>","tmdb":{"type":"movie","id":"689712","season":null,"vote_average":5.8,"vote_count":10},"modified":"2022-12-07T11:03:05.000Z","_image_preserved":true},{"id":"639010a5be31c1c97db2aefd","_id":"639010a5be31c1c97db2aefd","title":"Lừa Tình","origin_name":"Love Scams","slug":"lua-tinh","year":2018,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a2335e0fc277084dfd822","name":"Đài Loan","slug":"dai-loan"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Lừa Tình","link_embed":"https://vip.opstream16.com/share/552f5e345c9d523300ea73c6a65b0a6e","link_m3u8":"https://vip.opstream16.com/20221206/26987_2c1ca326/index.m3u8"}]}],"time":"101 phút","description":"<p>Bộ phim Lừa Tình – Love Scams xoay quanh sự nghiệp và scandal của nữ diễn viên hư hỏng Trương Vân. Cô bị giới truyền thông đeo bám và liên tục đã kích, do quá áp lực nên quyết định rút lui về nước. Cô bị tay săn ảnh Ah-K đeo bám, hắn là người đã lên kế hoạch gài bẫy cô với sự giúp đỡ của một người bạn là Hoàng Hạo. Ban đầu Hoàng Hạo không hứng thú với \\</p>","tmdb":{"type":"movie","id":"1081222","season":null,"vote_average":2,"vote_count":1},"modified":"2022-12-07T11:03:49.000Z","_image_preserved":true},{"id":"639010c8be31c1c97db2b0bc","_id":"639010c8be31c1c97db2b0bc","title":"Người Vợ Mất Tích","origin_name":"The Secret","slug":"nguoi-vo-mat-tich","year":2016,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"},{"id":"621674a770b58bba6858b852","name":"Ý","slug":"y"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Người Vợ Mất Tích","link_embed":"https://vip.opstream16.com/share/7b6787a3d154cf018b2e9edf0786f276","link_m3u8":"https://vip.opstream16.com/20221206/26989_5cfee689/index.m3u8"}]}],"time":"106 phút","description":"<p>Người Vợ Mất Tích - The Secret là câu chuyện của cặp vợ chồng Khải Phong và Thu Tiệp. Để kỉ niệm ngày cưới, hai người đã cùng nhau đi du lịch và trượt tuyết. Không may, người vợ Thu Tiệp qua đời vì tai nạn, điều này đã khiến cho Khải Phong hết sức đau lòng. Khải Phong ngày đêm mong chờ vợ quay về, tình yêu và sự chờ đợi của anh đã khiến linh hồn Thu Tiệp thực sự trở lại. Sau này, Khải Phong phát hiện, chỉ có những người thực sự yêu mến Thu Tiệp mới có thể trông thấy cô.</p>","tmdb":{"type":"movie","id":"394856","season":null,"vote_average":8,"vote_count":2},"modified":"2022-12-07T11:04:24.000Z","_image_preserved":true},{"id":"639010e5be31c1c97db2b284","_id":"639010e5be31c1c97db2b284","title":"Hoa Tiêu Chi Vị","origin_name":"Fagara","slug":"hoa-tieu-chi-vi","year":2019,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Hoa Tiêu Chi Vị","link_embed":"https://vip.opstream16.com/share/5564890753e533c5fb71cf81125fccfb","link_m3u8":"https://vip.opstream16.com/20221206/26986_54837320/index.m3u8"}]}],"time":"116 phút","description":"<p>Hoa Tiêu Chi Vị - Fagara là câu chuyện kể về Như Thụ - một cô gái đang cùng bố sống những chuỗi ngày bình yên với công việc yêu thích là lên kế hoạch cho một công ty du lịch. Những biến cố bất ngờ liên tiếp ập đến khi bố cô qua đời. Điều cô càng không thể ngờ là mình có tới 2 cô em gái cùng cha khác mẹ ở Đài Bắc và Trùng Khánh là Như Chi và Như Quả. Mặc dù 2 bố con sống cùng nhau bấy lâu nay nhưng đến bây giờ cô mới phát hiện ra bố mình đã từng có cuộc sống khác. Lần đầu tiên 3 chị em cô gặp nhau là trong đám tang của bố, trong mối quan hệ không thể giải thích. Tình cha con là cốt lõi của câu chuyện, còn số phận cuộc đời của mỗi cô con gái chính là hương vị đặc trưng của phim. Liệu họ có thể chấp nhận nhau? Liệu tình cảm ruột thịt máu mủ có được đong đầy?</p>","tmdb":{"type":"movie","id":"620210","season":null,"vote_average":7.3,"vote_count":11},"modified":"2022-12-07T11:04:53.000Z","_image_preserved":true},{"id":"63901103be31c1c97db2b450","_id":"63901103be31c1c97db2b450","title":"Nhân Chứng Thầm Lặng","origin_name":"Bodies At Rest","slug":"nhan-chung-tham-lang","year":2019,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Nhân Chứng Thầm Lặng","link_embed":"https://vip.opstream16.com/share/72417e4a6ce410ee495dc2978c405084","link_m3u8":"https://vip.opstream16.com/20221206/26990_61100de5/index.m3u8"}]}],"time":"93 phút","description":"<p>Nhân Chứng Thầm Lặng - Bodies At Rest xoay quanh cuộc chiến cân não giữa bác sĩ pháp y Trần Gia Hào và thực tập sinh Kiều Lâm với nhóm phạm tội sử dụng vũ khí nguy hiểm tại trung tâm pháp y. Vào đúng đêm giáng sinh, 3 kẻ đeo mặt lạ bất ngờ tấn công trung tâm, gây náo loạn và khiến nhiều người thương vong. Chúng giết hại bảo vệ và bắt bác sĩ Gia Hào cùng Kiều Lâm làm con tin, tên cầm đầu Santa muốn 2 người lấy viên đạn trong xác của một thi thể đặc biệt trong nhà xác. Sau khi tiến hành phẫu thuật, Gia Hào phát hiện ra chúng liên quan đến vụ án nghiêm trọng của giới xã hội đen nên anh đã tìm cách đánh lạc hướng chúng để tìm cơ hội tóm gọn bọn chúng.</p>","tmdb":{"type":"movie","id":"531368","season":null,"vote_average":6.37,"vote_count":92},"modified":"2022-12-07T11:05:23.000Z","_image_preserved":true},{"id":"63901122be31c1c97db2b636","_id":"63901122be31c1c97db2b636","title":"Dạ Yến","origin_name":"The Banquet","slug":"da-yen","year":2006,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Dạ Yến","link_embed":"https://vip.opstream16.com/share/6c04175de4297fbf49921a487dc1a2f6","link_m3u8":"https://vip.opstream16.com/20221206/26984_12ea7af3/index.m3u8"}]}],"time":"125 phút","description":"<p>Dạ Yến - The Banquet là bộ phim được lấy vào năm 907 sau Công nguyên, thời điểm mà triều chính nhà Đường đang gặp những vấn đề nghiêm trọng, không chỉ đơn giản là đang bị rạn nứt mà là còn đấu ngầm giữa các thế lực tranh giành quyền lực tàn nhẫn đến ghê người. Thái tử Vô Loan yêu Uyển Nhi, nhưng cha của hoàng đế lấy cô làm hoàng hậu. Vô Loan từ đó phiêu du thiên hạ, học nhảy và âm nhạc, hòa mình vào thiên nhiên để quên đi sự đời. Biến cố bắt đầu xảy đến nơi hoàng cung khi mà người chú ruột của thái tử đã giết cha của cậu ta, cướp ngôi và lấy luôn Hoàng hậu, thậm chí là y còn gửi đi rất nhiều sát thủ để giết Vu Loan. Thái tử thoát chết nhưng bị bắt. Hoàng đế sắp đặt lễ đăng quang của Uyển Nhi và áp giải Vu Loan đến một vùng đất xa xôi, sau đó ông ta tổ chức một bữa tiệc lúc nửa đêm vào ngày thứ 100 kỉ niệm ông ta lên ngôi. Thuốc độc, sự phản bội, sự trở lại của Vô Loan và tình yêu vô tận của Thanh Nữ dành cho Vô Loan đã mở ra một khoảnh khắc quyết định...</p>","tmdb":{"type":"movie","id":"14449","season":null,"vote_average":6.1,"vote_count":117},"modified":"2022-12-07T11:05:54.000Z","_image_preserved":true},{"id":"63901151be31c1c97db2b8e6","_id":"63901151be31c1c97db2b8e6","title":"Natra Ma Đồng Giáng Thế","origin_name":"Ne Zha","slug":"natra-ma-dong-giang-the","year":2019,"type":"hoathinh","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"},{"id":"620f84d291fa4af90ab6b3f4","name":"Bí ẩn","slug":"bi-an"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Natra Ma Đồng Giáng Thế","link_embed":"https://vip.opstream16.com/share/abb8cd30fbef5b0cf3402251455a9b56","link_m3u8":"https://vip.opstream16.com/20221206/26988_6d54f2cd/index.m3u8"}]}],"time":"110 phút","description":"<p>Bộ phim Natra Ma Đồng Giáng Thế - Ne Zha thuộc thể loại hoạt hình 3D của trung quốc thuộc thể loại Tiên hiệp phiêu lưu được công chiếu vào năm 2019. Bộ phim do Giảo Tử nhận trách nhiệm đạo diễn, với hai đồng biên kịch là Dịch Xảo và Nguỵ Vân. Phim được sản xuất dựa vào nguyên tác Phong thần diễn nghĩa, nội dung xoay quanh nhân vật Na Tra và con trai của Đông hải long vương là Ngao Bính. Câu chuyện truyền kỳ của Na Tra không may bị coi thành Ma hoàn chuyển thế, phải đối mặt với vận mệnh đầy trắc trở nhưng không chịu khuất phục.</p>","tmdb":{"type":"movie","id":"615453","season":null,"vote_average":7.9,"vote_count":716},"modified":"2022-12-07T11:06:41.000Z","_image_preserved":true},{"id":"6390116cbe31c1c97db2ba5c","_id":"6390116cbe31c1c97db2ba5c","title":"Cô Nàng Quyền Anh","origin_name":"A Girl Boxer","slug":"co-nang-quyen-anh","year":2004,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Cô Nàng Quyền Anh","link_embed":"https://vip.opstream16.com/share/da69515fd5a53b94ce79b9925f36b339","link_m3u8":"https://vip.opstream16.com/20221206/26983_c00730c5/index.m3u8"}]}],"time":"82 phút","description":"<p>Bộ phim Cô Nàng Quyền Anh - A Girl Boxer kể về câu chuyện một võ đài quyền anh trở thành nơi chiến đấu của tình yêu và sự giằng xé giữa tình yêu và tình thân. Tin Ha và Kin Fung sắp đính hôn, nhưng để thành hiện thực, Kin phải đánh bại cha cô, một võ sĩ quyền anh huyền thoại, trong một trận đấu quyền anh.</p>","tmdb":{"type":"movie","id":"668162","season":null,"vote_average":10,"vote_count":1},"modified":"2022-12-07T11:07:08.000Z","_image_preserved":true},{"id":"6390118abe31c1c97db2bc48","_id":"6390118abe31c1c97db2bc48","title":"Chúng Ta Chưa Từng","origin_name":"The Way We Weren't","slug":"chung-ta-chua-tung","year":2019,"type":"single","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Thuyết Minh #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Chúng Ta Chưa Từng","link_embed":"https://vip.opstream16.com/share/ba0d81f0e07c9e7e8af53293c93dc69b","link_m3u8":"https://vip.opstream16.com/20221206/26980_84c29102/index.m3u8"}]}],"time":"92 phút","description":"<p>Bộ phim Chúng Ta Chưa Từng - The Way We Weren't kể về câu chuyện dở khóc dở cười của cặp đôi Charlotte và Brandon. Hai người gặp nhau ngay sau khi mối quan hệ trước đó của họ tan vỡ, vì vậy, trong nỗ lực để khiến bản thân trở nên hấp dẫn hơn, họ phóng đại và nói dối về bản thân mình. Nhưng sau khi họ chuyển đến cùng nhau, tất cả sự lừa dối được làm sáng tỏ, tạo ra những tình huống vừa trớ trêu vừa hài hước.</p>","tmdb":{"type":"movie","id":"580522","season":null,"vote_average":5.175,"vote_count":20},"modified":"2022-12-07T11:07:38.000Z","_image_preserved":true},{"id":"639011afbe31c1c97db2be23","_id":"639011afbe31c1c97db2be23","title":"Ổ USB","origin_name":"Flashdrive","slug":"o-usb","year":2012,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Thuyết Minh","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Thuyết Minh #1","server_data":[{"name":"Full","slug":"full","filename":"Ổ USB","link_embed":"https://vip.opstream16.com/share/1d14f7a40b5c0e95f6b5529810582f23","link_m3u8":"https://vip.opstream16.com/20221206/26993_facaa36d/index.m3u8"}]}],"time":"62 phút","description":"<p>Bộ phim Ổ USB - Flashdrive kể về câu chuyện khi Ashley Romano - người sắp trở thành phóng viên tin tức tình cờ gặp một huyền thoại đô thị có tên là EL JARVE' DE ESCOBAR, cuộc sống của cô ấy đã bị đặt và